// src/data/experience.js
// ─────────────────────────────────────────────────────────
// Work experience and education timeline data.
// Update dates, roles, and descriptions to match your own.
// ─────────────────────────────────────────────────────────

export const WORK_EXPERIENCE = [
  {
  date: "July – Aug 2024",
  role: "Full Stack Developer Intern",
  org: "Hash Stack Solutions",
  desc: "Developed and optimized RESTful APIs using Node.js and Express.js, improving system performance and reducing response time. Built responsive frontend interfaces with React.js and integrated APIs for seamless data flow. Designed and optimized PostgreSQL databases and collaborated in an Agile development environment for feature development and debugging.",
  accentColor: "var(--accent)",
},
  {
  date: "Aug – Oct 2023",
  role: "Salesforce Developer Virtual Internship",
  org: "SmartInternz / AICTE",
  desc: "Successfully completed an 8-week Salesforce Developer Virtual Internship, gaining hands-on experience in Apex, Lightning Web Components (LWC), API integration, and process automation. Earned Super Badges including Apex Specialist, Process Automation Specialist, and Developer Super Set, demonstrating proficiency in real-world Salesforce development scenarios.",
  accentColor: "var(--accent)",
},
  {
  date: "July – Sep 2024",
  role: "Full Stack Web Development Training",
  org: "EduSkills",
  desc: "Completed full stack web development training focusing on frontend and backend technologies, including React.js, Node.js, and database integration, with hands-on project development experience.",
  accentColor: "var(--accent)",
}
];

export const EDUCATION = [
  {
    date: "2021 – 2025",
    role: "B.Tech in Computer Science (Artificial Intelligence & Machine Learning)",
    org: "Kakinada Institute Of Engineering and Technology",
    desc: "Focused on Artificial Intelligence and Machine Learning concepts along with programming in Python. Developed practical skills through academic projects and hands-on implementation of real-world applications.",
    accentColor: "var(--accent2)",
  },
  {
    date: "2019 – 2021",
    role: "Intermediate",
    org: "State Board",
    desc: "Completed higher secondary education with a focus on Mathematics, Physics, and Chemistry, strengthening analytical thinking and problem-solving skills.",
    accentColor: "var(--accent2)",
  },
];
